sql:
SELECT i.individual_id, ms.marital_status_name
FROM individuals i
INNER JOIN marital_statuses ms ON i.marital_status_id = ms.marital_status_id;

SELECT COUNT(*)
FROM individuals
WHERE education_id > 5;

SELECT i.individual_id, r.race_name
FROM individuals i
INNER JOIN races r ON i.race_id = r.race_id;

SELECT age
FROM individuals
WHERE age BETWEEN 25 AND 40 AND education_id > 12;

